INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('21-ket-tang-2',2,21,'KẾT TẦNG 2','Ket tang 2 - Tong hop va ket luan',21,'draft','2026-06-20T15:27:58Z','2026-06-20T15:27:58Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2737c64b-4dfc-438a-a4ce-86ade701d031','21-ket-tang-2',NULL,2,'21.1 Khi nào hệ sinh thái bắt đầu tự tạo đà? (The momentum threshold)','211-khi-nao-he-sinh-thai-bat-au-tu-tao-a-the-momentum-threshold',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('75127d06-df72-47cb-98d1-59340d42cad2','2737c64b-4dfc-438a-a4ce-86ade701d031',0,'text','Khép lại Tầng 2 của hệ điều hành **Dental Empire OS**, chúng ta không chỉ dừng lại ở việc vẽ ra các sơ đồ chiến lược hay cài đặt các phần mềm CRM vô tri. Mục tiêu tối hậu của tầng này là biến toàn bộ các điểm chạm truyền thông, trải nghiệm điều trị và kiến trúc cộng đồng thành một khối động cơ thống nhất, vận hành tự động và có khả năng tự sinh năng lượng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('512c20d4-732d-4e85-a578-6601f76629b7','2737c64b-4dfc-438a-a4ce-86ade701d031',1,'text','Để giúp nhà quản trị có cái nhìn toàn cảnh trước khi dịch chuyển bộ máy lên tầng nấc phát triển cao hơn, chương này sẽ bóc tách trạng thái tới hạn của bánh đà, các điểm rò rỉ năng lượng cần phòng tránh và lộ trình đưa bản đồ tư duy vào thực địa sàn vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d3e77e83-3c91-410b-b8e9-e421075ec3c4','2737c64b-4dfc-438a-a4ce-86ade701d031',2,'text','Bánh đà tăng trưởng không tự nhiên quay nhanh ngay từ ngày đầu tiên. Giai đoạn đầu luôn đòi hỏi sự kiên trì đầu tư công sức của khối *Marketing OS* và sự kỷ luật nghiêm ngặt của đội ngũ *Patient OS*. Tuy nhiên, hệ sinh thái sẽ đạt đến **Điểm tới hạn tự tạo đà (Self-Sustaining Threshold)** khi các chỉ số chuyển đổi hữu cơ hằng tháng chạm vào các mốc định lượng sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fec5ea60-004e-4f35-a16e-2d074002f891','2737c64b-4dfc-438a-a4ce-86ade701d031',3,'text','- **Chỉ số doanh thu hữu cơ vượt ngưỡng:** Khi trường dữ liệu `Revenue_from_Old_Patients` (Doanh thu từ khách hàng cũ) trên Dashboard của *Finance OS* liên tục chiếm từ **40% trở lên** trong tổng doanh thu ròng của phòng khám.- **Dòng khách giới thiệu (Referral Lead) tự vận hành:** Khi sản lượng ca lâm sàng mới được sản sinh trực tiếp từ lời giới thiệu của tệp cộng đồng hiện hữu chiếm ổn định từ **25% - 30%** tổng lượng lead đổ về, giúp chi phí sắm khách (CAC) toàn hệ thống giảm xuống mức kỷ lục.- **Đường ống Recall đạt trạng thái tự động hóa:** Khi hệ thống tin nhắn tự động chu kỳ sinh học y khoa (Zalo OA ZNS/SMS) kích hoạt ngầm, lọc sạch dữ liệu và tự động đổ Task đặt lịch hẹn về cho Lễ tân với tỷ lệ chuyển đổi cuộc hẹn thành công đạt mốc lớn hơn hoặc bằng 60% mà không cần ban giám đốc phải thúc ép nhân sự bằng tay.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0e5be469-7a5c-4d31-8f18-ecd716c52c2f','2737c64b-4dfc-438a-a4ce-86ade701d031',4,'text','Khi 3 điều kiện trên hội tụ, hệ sinh thái của bạn đã chính thức vượt qua lực cản ban đầu. Lúc này, năng lượng của bệnh nhân cũ đã quay ngược trở lại sưởi ấm và tạo ra niềm tin cho bệnh nhân mới, giúp cỗ máy phòng khám tự động tăng trưởng hữu cơ liên tục.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cc888fc3-fb95-44c8-b783-14b554ca63b1','21-ket-tang-2',NULL,2,'21.2 Điều gì làm hệ sinh thái yếu đi? (The friction &amp; Leak points)','212-ieu-gi-lam-he-sinh-thai-yeu-i-the-friction-amp-leak-points',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('37f6d7b7-c718-45af-81fe-d1661ac7f9f8','cc888fc3-fb95-44c8-b783-14b554ca63b1',5,'text','Trong quá trình vận hành thực địa, chỉ cần nhà quản trị lơ là một điểm chạm, toàn bộ năng lượng tích lũy của bánh đà sẽ lập tức bị triệt tiêu bởi các lực cản ma sát hệ thống. Dưới đây là 4 tác nhân chí mạng làm suy yếu sức khỏe hệ sinh thái:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c3cc088f-1a96-49f6-9292-905f55602998','cc888fc3-fb95-44c8-b783-14b554ca63b1',6,'image',NULL,'book/21-ket-tang-2/cdb2d4d2-5b3e-4fae-b457-684b55152a93-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d61e9f44-27ba-4db0-a639-4e18e9552597','21-ket-tang-2',NULL,2,'21.3 Từ master map sang vận hành thực tế (From blueprint to ground work)','213-tu-master-map-sang-van-hanh-thuc-te-from-blueprint-to-ground-work',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c7136521-f3f2-4e68-b63d-806041a616b3','d61e9f44-27ba-4db0-a639-4e18e9552597',7,'text','Để biến toàn bộ kiến trúc tư duy của Tầng 2 thành quy trình chạy thực địa hằng ngày tại phòng khám RHM, đội ngũ thực thi không được làm việc một cách ngẫu hứng. Mọi hành động bắt buộc phải tuân thủ lộ trình triển khai tuyến tính 4 bước dưới đây để đưa bản đồ Master Map vào mặt đất vận hành:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f16077e3-c40c-4d44-9d10-36e512cd8959','d61e9f44-27ba-4db0-a639-4e18e9552597',8,'image',NULL,'book/21-ket-tang-2/37db84cc-1adb-41d4-b03a-0046b62b8c4e-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ff31844f-8e3c-4251-aba3-6b85812fc310','21-ket-tang-2','d61e9f44-27ba-4db0-a639-4e18e9552597',3,'Làm sạch dữ liệu và cấu hình hệ thống công nghệ:','lam-sach-du-lieu-va-cau-hinh-he-thong-cong-nghe',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b172ef66-3653-4aea-bc33-d1f9709c1f0b','ff31844f-8e3c-4251-aba3-6b85812fc310',9,'text','***Bước 1: Chuẩn hóa.***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('24d25c3d-845f-40f8-9d81-6a389cc8c7b4','ff31844f-8e3c-4251-aba3-6b85812fc310',10,'text','Tiến hành rà soát toàn bộ kho dữ liệu hồ sơ bệnh nhân cũ trên CRM. Thực hiện cấu hình hệ thống thẻ Tag phân khúc thông minh (Patient_Segmentation) dựa trên loại hình dịch vụ mũi nhọn và mốc thời gian hoàn tất điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('afc6a65b-c5b2-4eda-ac0d-2fe295cb42d7','21-ket-tang-2','d61e9f44-27ba-4db0-a639-4e18e9552597',3,'Đóng gói bộ 7 tài sản hệ thống tiêu chuẩn:','ong-goi-bo-7-tai-san-he-thong-tieu-chuan',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a87a7c07-cc32-47b2-bf01-9310b9abbef7','afc6a65b-c5b2-4eda-ac0d-2fe295cb42d7',11,'text','***Bước 2: Vật chất hóa.***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5498f862-da34-47a3-b055-423f40bddd4c','afc6a65b-c5b2-4eda-ac0d-2fe295cb42d7',12,'text','Số hóa toàn bộ tri thức y khoa thành thư viện tài liệu số hữu hình (Cẩm nang trước/sau điều trị, Checklist hành động hằng ngày, kịch bản Recall Flow tự động). Thiết kế bao bì sang trọng cho các bộ giải pháp Homecare Kit tại quầy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('de0f1fcd-13ec-4a7b-9d62-88ed3973ed5a','21-ket-tang-2','d61e9f44-27ba-4db0-a639-4e18e9552597',3,'Kích hoạt Playbook và Đào tạo thực địa Role-play:','kich-hoat-playbook-va-ao-tao-thuc-ia-role-play',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('57d1b7c9-d480-4ce3-bbdf-d57a117bf192','de0f1fcd-13ec-4a7b-9d62-88ed3973ed5a',13,'text','***Bước 3: Huấn luyện.***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d183b94e-ee88-4d7c-bc8d-925e80398e43','de0f1fcd-13ec-4a7b-9d62-88ed3973ed5a',14,'text','Bàn giao kịch bản Sales Script và quy trình tiếp đón chuẩn SLA cho đội ngũ Lễ tân, CSKH và Trợ thủ. Tổ chức các buổi cọ xát tình huống thực tế (Role-play) trực tiếp sàn để đồng nhất ngôn ngữ tư vấn hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ea5a9028-ba05-46cc-9acc-cbf554056c3f','21-ket-tang-2','d61e9f44-27ba-4db0-a639-4e18e9552597',3,'Chạy chiến dịch thử nghiệm và tối ưu Dashboard KPI:','chay-chien-dich-thu-nghiem-va-toi-uu-dashboard-kpi',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('682d5322-69f0-44b5-b230-f510081cb06f','ea5a9028-ba05-46cc-9acc-cbf554056c3f',15,'text','*B****ước 4: Kích nổ Pilot.***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6f3d7469-7032-45b1-8155-ccf8df8a96b8','ea5a9028-ba05-46cc-9acc-cbf554056c3f',16,'text','Lựa chọn duy nhất một tệp khách hàng chủ lực (Ví dụ: tệp bệnh nhân sau tháo niềng) để chạy thử nghiệm chiến dịch phá băng và nhắc lịch tự động. Theo dõi sát sao các chỉ số chuyển đổi hằng tuần trên Dashboard trước khi nhân bản diện rộng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f883ed72-fe4b-4b50-ad12-693e6051ac9f','21-ket-tang-2',NULL,2,'21.4 Chuẩn bị bước vào tầng tiếp theo','214-chuan-bi-buoc-vao-tang-tiep-theo',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('89a8ee76-0916-41e5-a0a5-18b20bdbdb84','f883ed72-fe4b-4b50-ad12-693e6051ac9f',17,'text','Khi khép lại Tầng 2, phòng khám của bạn đã sở hữu một pháo đài giữ chân bệnh nhân vững chắc, một mạng lưới truyền thông sạch dựa trên tri thức và một cộng đồng hội viên gắn kết dài hạn. Chúng ta đã hoàn thiện toàn bộ cấu trúc hạ tầng trải nghiệm, lòng tin và dòng tiền hữu cơ ở cấp độ vận hành cơ sở.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('35353a6a-1c40-4b2a-a4f7-8a30716fd842','f883ed72-fe4b-4b50-ad12-693e6051ac9f',18,'text','Tuy nhiên, để đưa phòng khám bước vào trạng thái tăng trưởng bùng nổ, phá vỡ hoàn toàn giới hạn năng suất vật lý của ghế nha và sẵn sàng cho chiến lược nhân bản chuỗi quy mô lớn, chúng ta không thể chỉ quản trị bằng trải nghiệm dịch vụ. Hệ thống đòi hỏi một tầng kiến trúc tối cao hơn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ec99a533-9a00-468f-8984-e2a3b63126cd','f883ed72-fe4b-4b50-ad12-693e6051ac9f',19,'image',NULL,'book/21-ket-tang-2/58901b4c-6cb2-4b1e-859f-a848094deb4d-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2cfbd605-5f28-4a49-955a-714567f6b40c','f883ed72-fe4b-4b50-ad12-693e6051ac9f',20,'text','**Mantra chuyển tầng:** *"Chiến lược hay mà không có hệ thống thực thi thì chỉ là một giấc mơ hão huyền; quy trình chuẩn trên giấy mà thiếu đi công cụ giám sát con người sẽ nhanh chóng biến thành một trò đùa vận hành."*',NULL,NULL,NULL,NULL,NULL);
